import type { CareerQuestion } from "./social-worker-questions";

export const socialWorkerQuestionsBatch26: CareerQuestion[] = [
  { id: "sw-1376", stem: "In DBT, what is the primary purpose of the 'distress tolerance' skills module?", options: ["To eliminate all distressing emotions", "To help clients survive crisis situations without making them worse by using acceptance-based and crisis survival strategies", "To teach clients to avoid all stressful situations", "To replace medication management"], correctIndex: 1, rationale: "DBT distress tolerance skills help clients tolerate painful emotions and crises without engaging in destructive behaviors. Skills include TIPP (Temperature, Intense exercise, Paced breathing, Progressive relaxation), distraction (ACCEPTS), self-soothing, improving the moment (IMPROVE), and radical acceptance. The goal is not to eliminate distress but to survive it without worsening the situation.", difficulty: 2, category: "Clinical Practice", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1377", stem: "A client in ACT therapy says, 'I can't do anything because I'm too anxious.' The therapist's best response using ACT principles would be:", options: ["Challenge the irrational belief directly", "Help the client notice the thought as a thought ('I'm having the thought that I can't do anything') and explore whether they can take valued action even while experiencing anxiety", "Reassure the client that anxiety will go away soon", "Prescribe relaxation exercises to eliminate the anxiety"], correctIndex: 1, rationale: "ACT uses cognitive defusion to help clients observe thoughts without being controlled by them. Rather than challenging or eliminating anxiety, ACT encourages psychological flexibility—the ability to take values-driven action even in the presence of difficult thoughts and feelings. The technique of prefacing thoughts with 'I'm having the thought that...' creates distance between the person and the thought.", difficulty: 3, category: "Clinical Practice", topic: "ACT", questionType: "CASE_VIGNETTE" },
  { id: "sw-1378", stem: "During an EMDR session, a client becomes highly distressed and dissociative during the desensitization phase. What is the social worker's priority action?", options: ["Continue bilateral stimulation to push through the distress", "Stop bilateral stimulation, use grounding techniques to stabilize the client, and ensure the client is oriented to the present before proceeding or closing the session safely", "End the session immediately and refer to psychiatry", "Tell the client they are overreacting"], correctIndex: 1, rationale: "When a client dissociates during EMDR, the clinician must stop bilateral stimulation and use grounding and stabilization techniques (safe place visualization, orienting to the room, breathing exercises) to bring the client back to a window of tolerance. Client safety is paramount. The clinician should assess whether to continue processing or close the session with adequate stabilization. Pushing through dissociation can retraumatize the client.", difficulty: 4, category: "Trauma-Informed Care", topic: "EMDR", questionType: "CASE_VIGNETTE" },
  { id: "sw-1379", stem: "A 6-year-old child who witnessed domestic violence is referred for therapy. Which intervention approach is most developmentally appropriate?", options: ["Traditional talk therapy focusing on cognitive restructuring", "Play therapy, which allows the child to express and process traumatic experiences through symbolic play, art, and storytelling in a safe therapeutic environment", "Exposure-based therapy with detailed verbal recounting of the violence", "Group therapy with adult domestic violence survivors"], correctIndex: 1, rationale: "Play therapy is the most developmentally appropriate intervention for young children because children communicate and process experiences primarily through play rather than verbal expression. Through play, children can safely express emotions, reenact traumatic events symbolically, develop coping skills, and work through trauma at their own pace. The therapist provides a safe, accepting environment and uses reflective responses to facilitate healing.", difficulty: 2, category: "Child & Family Services", topic: "Play Therapy", questionType: "CASE_VIGNETTE" },
  { id: "sw-1380", stem: "In group therapy, a member consistently monopolizes the conversation and other members appear disengaged. What should the group facilitator do?", options: ["Allow the behavior to avoid conflict", "Use group process skills to redirect, such as acknowledging the member's contributions while inviting others to share, and later explore the dynamics privately with the monopolizing member", "Remove the member from the group", "Publicly confront the member about their behavior"], correctIndex: 1, rationale: "Effective group facilitation requires balancing individual needs with group process. The facilitator should use gatekeeping skills—acknowledging the monopolizing member while drawing in quieter members ('Thank you for sharing. I'd like to hear from others as well.'). Privately discussing the pattern with the individual member can address the behavior without shaming. Understanding the underlying need (anxiety, need for control) informs the intervention.", difficulty: 3, category: "Clinical Practice", topic: "Group Dynamics", questionType: "CASE_VIGNETTE" },
  { id: "sw-1381", stem: "A client presents with suicidal ideation, a specific plan involving firearms, and access to the weapon. Which element of the crisis assessment indicates the highest level of risk?", options: ["Having suicidal thoughts", "The combination of suicidal ideation with a specific lethal plan and access to the identified means, which constitutes an imminent risk requiring immediate intervention including means restriction", "A history of depression", "Expressing hopelessness"], correctIndex: 1, rationale: "Suicide risk assessment examines ideation, plan, means, intent, and timeline. The combination of a specific plan with access to lethal means (especially firearms, which have the highest lethality rate) constitutes the highest risk level. Immediate intervention includes means restriction (safely removing or securing the firearm), safety planning, and possible hospitalization. Means restriction is one of the most evidence-based suicide prevention strategies.", difficulty: 4, category: "Crisis Intervention", topic: "Suicide Risk", questionType: "PRIORITIZATION" },
  { id: "sw-1382", stem: "What is 'radical acceptance' in the context of DBT?", options: ["Approving of everything that happens", "Fully acknowledging and accepting reality as it is in the present moment without judgment or attempts to change it, while recognizing that acceptance does not mean approval", "Giving up on making changes", "A passive approach to life problems"], correctIndex: 1, rationale: "Radical acceptance in DBT means completely accepting the present moment reality without fighting it. It does not mean approval, agreement, or passivity. Rather, it reduces suffering caused by fighting against unchangeable reality. Pain is inevitable; suffering (pain plus non-acceptance) is optional. Radical acceptance frees emotional energy for effective problem-solving and values-based action.", difficulty: 2, category: "Clinical Practice", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1383", stem: "A social worker suspects a colleague is experiencing burnout and notices declining quality of client care. What is the most ethical course of action?", options: ["Ignore it as it is not their responsibility", "Approach the colleague with compassion, express concern about their well-being, encourage them to seek support, and if client care remains compromised, consult with a supervisor about the situation", "Report the colleague to the licensing board immediately", "Take over the colleague's caseload without discussion"], correctIndex: 1, rationale: "The NASW Code of Ethics requires social workers to address impairment in colleagues. The first step is a compassionate conversation expressing concern. If the colleague does not take corrective action and client welfare is at risk, consulting with a supervisor is appropriate. This approach balances collegial support with the ethical obligation to protect clients. Immediate licensing board reports are premature without first addressing the issue directly.", difficulty: 3, category: "Ethics & Professional Boundaries", topic: "Burnout Prevention", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1384", stem: "In ACT, 'values clarification' exercises help clients:", options: ["Identify their moral failings", "Discover what matters most to them and use these values as a compass for guiding meaningful behavioral choices, even in the presence of difficult thoughts and emotions", "Set specific measurable goals", "Eliminate conflicting values"], correctIndex: 1, rationale: "In ACT, values are freely chosen, ongoing directions for living (not goals to be achieved). Values clarification helps clients identify what gives their life meaning across domains (relationships, work, health, spirituality). Values then serve as a motivational compass for committed action. Unlike goals, values cannot be completed—they provide ongoing direction. This process is central to ACT's aim of increasing psychological flexibility and living a rich, meaningful life.", difficulty: 2, category: "Clinical Practice", topic: "ACT", questionType: "MCQ" },
  { id: "sw-1385", stem: "A domestic violence survivor asks the social worker to contact their abusive partner to mediate the conflict. How should the social worker respond?", options: ["Agree to mediate as the client requested", "Explain that mediation is contraindicated in domestic violence situations due to the inherent power imbalance, discuss safety planning, and explore the client's underlying needs and concerns that prompted the request", "Refuse and terminate the therapeutic relationship", "Contact the partner without informing the client"], correctIndex: 1, rationale: "Mediation is contraindicated in domestic violence because it assumes equal power between parties, which does not exist in abusive relationships. The abuser may use mediation to further intimidate or manipulate the victim. The social worker should educate the client about why mediation is unsafe, validate the underlying need (perhaps for resolution or communication), explore alternative options, and prioritize safety planning.", difficulty: 3, category: "Crisis Intervention", topic: "Domestic Violence", questionType: "APPLIED_ETHICS" },
  { id: "sw-1386", stem: "Which of the following best describes the 'eight phases' of EMDR therapy?", options: ["Eight separate sessions of eye movement desensitization", "A structured protocol including history-taking, preparation, assessment, desensitization, installation, body scan, closure, and reevaluation that guides the processing of traumatic memories", "Eight types of bilateral stimulation", "Eight categories of trauma"], correctIndex: 1, rationale: "EMDR's eight phases are: (1) History and treatment planning—identifying targets; (2) Preparation—building resources and explaining the process; (3) Assessment—activating the target memory with image, negative cognition, positive cognition, VOC, SUD, emotions, and body sensations; (4) Desensitization—bilateral stimulation to process the memory; (5) Installation—strengthening the positive cognition; (6) Body scan—checking for residual somatic disturbance; (7) Closure—stabilization; (8) Reevaluation—assessing treatment effects.", difficulty: 3, category: "Trauma-Informed Care", topic: "EMDR", questionType: "MCQ" },
  { id: "sw-1387", stem: "A social worker at a homeless shelter notices that many clients cycle in and out repeatedly. Which intervention model best addresses chronic homelessness?", options: ["Emergency shelter stays with time limits", "Housing First, which provides immediate access to permanent housing without preconditions such as sobriety or treatment compliance, combined with wraparound support services", "Requiring completion of substance use treatment before housing", "Transitional housing with mandatory life skills classes"], correctIndex: 1, rationale: "Housing First is an evidence-based approach that provides permanent housing immediately without requiring sobriety, treatment compliance, or program participation as prerequisites. Research consistently shows Housing First reduces chronic homelessness, emergency room visits, hospitalizations, and overall costs. Wraparound services (case management, mental health, substance use treatment) are offered but not mandated. This approach recognizes that stable housing is a foundation for addressing other issues.", difficulty: 3, category: "Clinical Practice", topic: "Homelessness Interventions", questionType: "CASE_VIGNETTE" },
  { id: "sw-1388", stem: "In directive play therapy, the therapist:", options: ["Allows the child to lead all play activities", "Structures activities and introduces specific therapeutic themes, games, or materials designed to address the child's identified treatment goals while maintaining a supportive therapeutic relationship", "Only observes without interacting", "Uses play as a reward for good behavior"], correctIndex: 1, rationale: "Directive play therapy involves the therapist selecting and structuring activities to target specific therapeutic goals. This contrasts with non-directive (child-centered) play therapy where the child leads. Directive techniques include therapeutic board games, sand tray directives, puppet scenarios, art activities with specific prompts, and bibliotherapy. The therapist maintains a warm relationship while guiding the therapeutic process toward treatment objectives.", difficulty: 3, category: "Child & Family Services", topic: "Play Therapy", questionType: "MCQ" },
  { id: "sw-1389", stem: "A social worker conducting a suicide risk assessment should prioritize which of the following protective factors?", options: ["High income level", "Reasons for living, social connectedness, access to mental health care, problem-solving skills, and cultural or religious beliefs that discourage suicide", "Physical fitness", "Educational attainment"], correctIndex: 1, rationale: "Protective factors against suicide include: reasons for living (children, pets, future goals), social connectedness (supportive relationships, community belonging), access to effective mental health care, coping and problem-solving skills, restricted access to lethal means, and cultural or religious beliefs that provide meaning and discourage suicide. Assessing protective factors alongside risk factors provides a more complete picture and informs safety planning by building on existing strengths.", difficulty: 2, category: "Crisis Intervention", topic: "Suicide Risk", questionType: "MCQ" },
  { id: "sw-1390", stem: "An undocumented immigrant family is afraid to seek mental health services due to fear of deportation. The social worker should:", options: ["Report their immigration status to authorities", "Provide clear information about confidentiality protections, connect them with immigration-friendly service providers, and address barriers to access while respecting their autonomy in decision-making", "Refuse to serve them without documentation", "Insist they obtain legal status before receiving services"], correctIndex: 1, rationale: "Social workers have an ethical obligation to serve all people regardless of immigration status. Key actions include: explaining confidentiality protections, clarifying that mental health records are not shared with immigration enforcement, connecting families with community organizations experienced in serving immigrant populations, offering services in their language, understanding the impact of immigration stress on mental health, and advocating for policies that protect access to care.", difficulty: 3, category: "Diversity, Equity & Inclusion", topic: "Immigration Social Work", questionType: "APPLIED_ETHICS" },
  { id: "sw-1391", stem: "Which DBT skill teaches clients to be effective in interpersonal situations while maintaining self-respect?", options: ["Mindfulness meditation only", "The DEAR MAN, GIVE, FAST skills, which provide a structured approach to asking for needs (DEAR MAN), maintaining relationships (GIVE), and preserving self-respect (FAST) in interpersonal interactions", "Cognitive restructuring", "Free association"], correctIndex: 1, rationale: "DBT interpersonal effectiveness skills include three acronyms: DEAR MAN (Describe, Express, Assert, Reinforce, stay Mindful, Appear confident, Negotiate) for objective effectiveness; GIVE (Gentle, Interested, Validate, Easy manner) for relationship effectiveness; and FAST (Fair, no Apologies unnecessary, Stick to values, Truthful) for self-respect effectiveness. These skills help clients balance getting their needs met, maintaining relationships, and preserving self-respect.", difficulty: 2, category: "Clinical Practice", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1392", stem: "A social worker notices they are feeling emotionally exhausted, cynical about clients, and questioning the impact of their work. These symptoms most likely indicate:", options: ["Normal work stress", "Professional burnout, characterized by emotional exhaustion, depersonalization, and reduced sense of personal accomplishment, requiring proactive self-care and organizational support interventions", "Clinical depression requiring medication", "A need for a different career"], correctIndex: 1, rationale: "Maslach's three dimensions of burnout are: emotional exhaustion (feeling drained), depersonalization/cynicism (detachment from clients), and reduced personal accomplishment (questioning effectiveness). Burnout differs from general stress in its chronic nature and specific work-related focus. Interventions include: individual self-care (boundaries, supervision, personal therapy), organizational changes (manageable caseloads, supportive supervision, professional development), and systemic advocacy for better working conditions.", difficulty: 1, category: "Ethics & Professional Boundaries", topic: "Burnout Prevention", questionType: "MCQ" },
  { id: "sw-1393", stem: "In a research study examining the effectiveness of a new social work intervention, what does 'random assignment' accomplish?", options: ["It ensures all participants are the same", "It distributes both known and unknown confounding variables equally between treatment and control groups, strengthening causal inference about the intervention's effectiveness", "It eliminates the need for a control group", "It guarantees the intervention will work"], correctIndex: 1, rationale: "Random assignment is a hallmark of experimental (RCT) design that distributes confounding variables—both measured and unmeasured—equally across groups. This allows researchers to attribute observed differences in outcomes to the intervention rather than pre-existing group differences. Without random assignment (as in quasi-experimental designs), selection bias threatens internal validity. Random assignment strengthens causal claims about intervention effectiveness.", difficulty: 3, category: "Assessment & Intervention Planning", topic: "Research Methods", questionType: "MCQ" },
  { id: "sw-1394", stem: "A child in play therapy repeatedly builds a tower and then violently knocks it down while saying 'bad, bad, bad.' The play therapist should:", options: ["Stop the child from destructive play", "Recognize this as potential symbolic communication about the child's experiences, reflect the child's emotions and themes, and track the play to understand the child's internal world without prematurely interpreting or interrupting the process", "Ignore the behavior completely", "Ask the child directly what the play means"], correctIndex: 1, rationale: "In play therapy, children's repetitive play often represents symbolic processing of their experiences. The therapist tracks the play (describes what the child is doing), reflects feelings ('You're really angry at that tower'), and returns responsibility to the child. Prematurely interpreting or stopping the play can disrupt the therapeutic process. The therapist allows the child to use play as their natural language for expressing and processing difficult experiences.", difficulty: 3, category: "Child & Family Services", topic: "Play Therapy", questionType: "CASE_VIGNETTE" },
  { id: "sw-1395", stem: "What is the primary goal of ACT's 'defusion' techniques?", options: ["To prove that negative thoughts are irrational", "To create psychological distance between the person and their thoughts so that thoughts are experienced as mental events rather than literal truths that must be obeyed or eliminated", "To suppress unwanted thoughts", "To replace negative thoughts with positive ones"], correctIndex: 1, rationale: "Cognitive defusion in ACT aims to change the relationship with thoughts rather than their content. Techniques include: saying a thought in a silly voice, repeating a word until it loses meaning, prefacing with 'I notice I'm having the thought that...', visualizing thoughts as leaves on a stream, and thanking the mind for its input. Defusion reduces the believability and impact of thoughts without challenging their accuracy, allowing greater behavioral flexibility.", difficulty: 3, category: "Clinical Practice", topic: "ACT", questionType: "MCQ" },
  { id: "sw-1396", stem: "A social worker is developing a safety plan with a domestic violence survivor. Which elements should be included?", options: ["Only information about local shelters", "A comprehensive plan including identification of warning signs, safe rooms in the home, essential items to take when leaving, safe people to contact, emergency numbers, safe places to go, legal protections available, and plans for children and pets", "A written contract promising not to return to the abuser", "Only a police phone number"], correctIndex: 1, rationale: "Comprehensive domestic violence safety planning includes: recognizing warning signs of escalating violence, identifying safe areas in the home (avoiding kitchens and bathrooms with hard surfaces), packing an emergency bag (documents, medications, money, phone), memorizing important numbers, identifying trusted people for support, knowing shelter locations, understanding legal options (protection orders), planning for children's safety, addressing pet safety, and developing a technology safety plan. The plan should be personalized and stored safely.", difficulty: 2, category: "Crisis Intervention", topic: "Domestic Violence", questionType: "PRIORITIZATION" },
  { id: "sw-1397", stem: "In EMDR therapy, the 'Subjective Units of Disturbance Scale' (SUDS) is used to:", options: ["Diagnose PTSD severity", "Measure the client's self-reported level of disturbance associated with a target memory on a 0-10 scale, tracking changes in distress throughout the desensitization phase of treatment", "Assess overall mental health functioning", "Determine insurance reimbursement levels"], correctIndex: 1, rationale: "The SUDS (0-10 scale, where 0 is no disturbance and 10 is the worst disturbance imaginable) is used during EMDR's assessment and desensitization phases to measure the client's subjective distress related to the target memory. It provides a quantifiable way to track progress within and across sessions. The goal of desensitization is to reduce the SUDS to 0 or 1 (ecological validity permitting). It helps the clinician determine when processing is complete.", difficulty: 2, category: "Trauma-Informed Care", topic: "EMDR", questionType: "MCQ" },
  { id: "sw-1398", stem: "A social worker leading a psychoeducation group notices two members forming a subgroup that whispers during sessions and excludes others. This dynamic is best understood as:", options: ["Normal socializing behavior", "A subgrouping phenomenon that can undermine group cohesion, trust, and therapeutic effectiveness, requiring the facilitator to address the dynamic openly and explore its impact on the group process", "Evidence that the group is too large", "A sign that those members should be removed"], correctIndex: 1, rationale: "Subgrouping is a common group dynamic that can fragment the group, create insider/outsider dynamics, and undermine cohesion and trust. The facilitator should address this process-level issue by naming the observed dynamic ('I notice there are side conversations happening') and exploring its meaning and impact on the group. Strategies include adjusting seating, using structured activities that mix members, and establishing group norms about inclusive communication.", difficulty: 3, category: "Clinical Practice", topic: "Group Dynamics", questionType: "CASE_VIGNETTE" },
  { id: "sw-1399", stem: "Which of the following self-care strategies is most important for preventing compassion fatigue in social workers?", options: ["Working longer hours to resolve cases faster", "Maintaining a consistent practice of self-awareness, professional boundaries, regular supervision, peer support, and balanced engagement in restorative activities outside of work", "Avoiding emotional connection with clients", "Taking on only easy cases"], correctIndex: 1, rationale: "Compassion fatigue prevention requires a multifaceted approach: self-awareness (monitoring one's own emotional state), professional boundaries (separating work and personal life), regular clinical supervision (processing difficult cases), peer support (collegial connections), restorative activities (exercise, hobbies, relationships, spirituality), adequate rest, continuing education on trauma-informed self-care, and organizational factors (manageable caseloads, supportive culture). Emotional connection with clients is essential to effective practice—the key is balanced engagement.", difficulty: 1, category: "Ethics & Professional Boundaries", topic: "Self-Care for Social Workers", questionType: "MCQ" },
  { id: "sw-1400", stem: "A homeless client with schizophrenia refuses medication and housing services. Using a harm reduction approach, the social worker should:", options: ["Seek involuntary commitment immediately", "Meet the client where they are, offer low-barrier services, maintain the therapeutic relationship, provide information about available resources without coercion, and work to reduce immediate risks to health and safety", "Discharge the client from services", "Require medication compliance before offering any assistance"], correctIndex: 1, rationale: "Harm reduction with homeless individuals respects autonomy while reducing risks. The social worker maintains engagement through consistent outreach, offers low-barrier services (drop-in centers, street medicine, food), addresses immediate needs (warm clothing, wound care), provides information about housing and treatment options without mandating them, and builds trust over time. This approach recognizes that engagement and trust-building precede behavior change and that forcing services can drive clients away from care.", difficulty: 3, category: "Clinical Practice", topic: "Homelessness Interventions", questionType: "CASE_VIGNETTE" },
  { id: "sw-1401", stem: "What distinguishes a 'quasi-experimental' research design from a true experiment?", options: ["Quasi-experiments use larger sample sizes", "Quasi-experiments lack random assignment to treatment and control groups, which limits the ability to make causal inferences but may be more feasible and ethical in real-world social work research settings", "Quasi-experiments do not use measurement tools", "There is no meaningful difference"], correctIndex: 1, rationale: "Quasi-experimental designs share features with true experiments (comparison groups, pre/post measurement) but lack random assignment. This means pre-existing differences between groups may confound results, limiting causal conclusions. However, quasi-experiments are often more feasible in social work settings where random assignment may be impractical or unethical. Common designs include nonequivalent control group and interrupted time series. Researchers use statistical controls to address selection bias.", difficulty: 3, category: "Assessment & Intervention Planning", topic: "Research Methods", questionType: "MCQ" },
  { id: "sw-1402", stem: "In DBT's biosocial theory, emotional dysregulation results from:", options: ["Poor parenting alone", "The transaction between a biologically based emotional vulnerability (high sensitivity, strong reactivity, slow return to baseline) and an invalidating environment that dismisses, punishes, or intermittently reinforces emotional expressions", "Genetic factors exclusively", "Childhood trauma only"], correctIndex: 1, rationale: "DBT's biosocial theory posits that emotional dysregulation develops through the ongoing transaction between biological vulnerability (heightened emotional sensitivity, intense reactions, slow return to baseline) and an invalidating environment (one that communicates that emotional responses are wrong, overblown, or unacceptable). Neither factor alone causes the disorder—it is the interaction that leads to deficits in emotion regulation, distress tolerance, interpersonal effectiveness, and self-management skills.", difficulty: 3, category: "Clinical Practice", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1403", stem: "A social worker receives a referral for an immigrant family whose child is struggling in school. The family speaks limited English. What is the first priority?", options: ["Administer standardized English assessments", "Arrange for a qualified interpreter and conduct a culturally responsive assessment that considers acculturation stress, immigration trauma, language barriers, and the family's strengths and support systems", "Report the family to child protective services", "Refer the child for special education testing immediately"], correctIndex: 1, rationale: "Working with immigrant families requires cultural responsiveness and language access. The first priority is ensuring communication through a qualified interpreter (not the child or family member). Assessment should consider: immigration and acculturation stress, potential trauma (pre-migration, migration journey, post-migration), language acquisition as a developmental process, cultural differences in educational expectations, family strengths and resilience, and community resources. Standardized assessments may not be valid for culturally and linguistically diverse populations.", difficulty: 2, category: "Diversity, Equity & Inclusion", topic: "Immigration Social Work", questionType: "CASE_VIGNETTE" },
  { id: "sw-1404", stem: "During the 'storming' stage of group development (Tuckman's model), the social worker should:", options: ["Avoid all conflict in the group", "Normalize conflict as a natural part of group development, facilitate constructive expression of differences, reinforce group norms, and help members develop conflict resolution skills while maintaining safety", "Disband the group and start over", "Add new members to change the dynamic"], correctIndex: 1, rationale: "Tuckman's storming stage involves conflict, competition, and resistance as members test boundaries and negotiate roles. The facilitator should: normalize conflict as healthy group development, maintain safety while allowing productive disagreement, reinforce ground rules, model respectful communication, help members express concerns directly, and use the conflict as learning opportunities. Successfully navigating storming leads to norming (cohesion) and performing (productive work). Avoiding conflict prevents group maturation.", difficulty: 3, category: "Clinical Practice", topic: "Group Dynamics", questionType: "CASE_VIGNETTE" },
  { id: "sw-1405", stem: "A client with PTSD reports nightmares, hypervigilance, and emotional numbing after a car accident. Which EMDR target would typically be addressed first?", options: ["The client's earliest childhood memory", "The most disturbing aspect of the car accident memory, identified through the assessment phase as having the highest subjective disturbance, as this is typically the primary target in single-incident trauma", "Future anticipated driving situations only", "Pleasant memories to build resources"], correctIndex: 1, rationale: "In EMDR for single-incident trauma, the standard protocol targets the traumatic event first. During assessment (Phase 3), the client identifies the most disturbing image, negative cognition, emotions, and body sensations associated with the car accident. The target with the highest SUDS is typically processed first. While resource development may precede trauma processing for complex trauma, single-incident PTSD typically begins with the index trauma. Future templates and triggers are addressed after the primary memory is processed.", difficulty: 4, category: "Trauma-Informed Care", topic: "EMDR", questionType: "CASE_VIGNETTE" },
  { id: "sw-1406", stem: "What is the Columbia Suicide Severity Rating Scale (C-SSRS) and its purpose?", options: ["A self-administered depression questionnaire", "A standardized, evidence-based tool that assesses the severity and intensity of suicidal ideation, the nature of suicidal behavior, and lethality of attempts through structured interview questions, used widely across clinical settings", "A measure of anxiety symptoms", "A personality assessment tool"], correctIndex: 1, rationale: "The C-SSRS is a structured interview tool that classifies suicidal ideation from wish to die (least severe) through active ideation with specific plan and intent (most severe). It also assesses suicidal behavior (actual, interrupted, aborted attempts; preparatory behavior). The tool is widely adopted across healthcare, military, schools, and crisis settings. It provides a common language for assessing and communicating suicide risk and is supported by extensive research validation.", difficulty: 2, category: "Crisis Intervention", topic: "Suicide Risk", questionType: "MCQ" },
  { id: "sw-1407", stem: "A social worker practicing ACT uses the 'passengers on the bus' metaphor. This metaphor teaches clients about:", options: ["Public transportation advocacy", "The concept that the client is the bus driver moving toward valued directions, while difficult thoughts and feelings are passengers who may shout and threaten but cannot actually control where the bus goes if the driver stays committed to their values", "Group therapy dynamics", "Passive coping strategies"], correctIndex: 1, rationale: "The 'passengers on the bus' metaphor illustrates that the client (driver) can move in valued directions even when difficult thoughts and feelings (passengers) are present and noisy. The passengers may say threatening things ('Turn back!' 'You can't do this!'), but they cannot actually steer the bus. The client doesn't have to fight the passengers or wait for them to leave—they can drive toward their values with the passengers still on board. This teaches willingness and values-directed action.", difficulty: 2, category: "Clinical Practice", topic: "ACT", questionType: "MCQ" },
  { id: "sw-1408", stem: "A social worker discovers that a client experiencing domestic violence has an active protection order but the abuser has been contacting them through social media. What should the social worker do?", options: ["Advise the client to respond to the messages", "Help the client document the violations, inform them of their right to report the violations to law enforcement, assist with technology safety planning, and coordinate with the client's legal advocate", "Ignore the situation since it is a legal matter", "Contact the abuser directly to warn them"], correctIndex: 1, rationale: "Social media contact may violate a protection order. The social worker should: help the client document all contact (screenshots with dates), inform the client of their right to report violations to law enforcement, assist with technology safety (privacy settings, blocking, new accounts if needed), coordinate with the client's legal advocate or attorney, review and update the safety plan, and address the emotional impact of continued contact. The social worker should not contact the abuser directly.", difficulty: 3, category: "Crisis Intervention", topic: "Domestic Violence", questionType: "CASE_VIGNETTE" },
  { id: "sw-1409", stem: "Which research method is most appropriate for exploring the lived experiences of social workers dealing with burnout?", options: ["Randomized controlled trial", "Qualitative phenomenological research, which uses in-depth interviews to capture and understand the essence of participants' subjective experiences and the meaning they attach to burnout", "Large-scale survey research", "Single-subject design"], correctIndex: 1, rationale: "Phenomenological research is a qualitative method specifically designed to explore the essence of lived experience. It uses in-depth, open-ended interviews to understand how participants experience and make meaning of a phenomenon. For studying social worker burnout experiences, this method captures rich descriptions of the emotional, cognitive, physical, and relational dimensions of burnout that quantitative methods might miss. Data analysis involves identifying themes across participants' descriptions.", difficulty: 3, category: "Assessment & Intervention Planning", topic: "Research Methods", questionType: "MCQ" },
  { id: "sw-1410", stem: "In Erikson's psychosocial stage of 'generativity vs. stagnation,' which developmental task is primary?", options: ["Establishing intimate relationships", "Contributing to the next generation through parenting, mentoring, community involvement, or creative productivity, leading to a sense of purpose and meaning in middle adulthood", "Developing personal identity", "Achieving ego integrity"], correctIndex: 1, rationale: "Generativity vs. stagnation (approximately ages 40-65) centers on the need to contribute to something beyond oneself. Generative adults invest in raising children, mentoring younger generations, contributing to their community, creating lasting works, or engaging in meaningful productivity. Those who fail to find ways to contribute may experience stagnation—feeling unproductive, disconnected, and unfulfilled. This stage reflects the human need for purpose and legacy.", difficulty: 1, category: "Human Development", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1411", stem: "A social worker is working with a client experiencing homelessness who has untreated diabetes. The most comprehensive intervention would involve:", options: ["Referring only to a medical clinic", "Coordinating across systems to simultaneously address housing, healthcare access, diabetes management education, insurance enrollment, food security, and social support while building on the client's strengths and goals", "Focusing exclusively on finding housing first", "Providing diabetes education pamphlets"], correctIndex: 1, rationale: "Homelessness and chronic health conditions require integrated, multi-system intervention. The social worker coordinates: housing resources (Housing First, rapid rehousing), healthcare access (community health centers, street medicine), insurance enrollment (Medicaid, marketplace), diabetes-specific needs (medication access, glucose monitoring, dietary needs), food security (food banks, SNAP), and social support (peer connections, case management). Addressing one need without the others is insufficient—housing instability makes diabetes management nearly impossible.", difficulty: 3, category: "Clinical Practice", topic: "Homelessness Interventions", questionType: "CASE_VIGNETTE" },
  { id: "sw-1412", stem: "What is 'vicarious traumatization' and how does it differ from burnout?", options: ["They are the same thing", "Vicarious traumatization involves a transformation in the helper's inner experience—changes in worldview, beliefs about safety, trust, and meaning—resulting from empathic engagement with traumatized clients, while burnout is related to workload and organizational stress", "Vicarious traumatization only affects new clinicians", "It is a diagnosable mental health disorder"], correctIndex: 1, rationale: "Vicarious traumatization (Pearlman & Saakvitne) involves cumulative cognitive shifts in the helper's frame of reference—disrupted beliefs about safety, trust, esteem, intimacy, and control. It differs from burnout (which relates to workplace demands, emotional exhaustion, and organizational factors) and secondary traumatic stress (which involves PTSD-like symptoms from hearing traumatic material). VT is an occupational hazard of trauma work requiring ongoing self-awareness, supervision, and organizational support.", difficulty: 4, category: "Ethics & Professional Boundaries", topic: "Self-Care for Social Workers", questionType: "MCQ" },
  { id: "sw-1413", stem: "A 4-year-old in play therapy selects aggressive toys and enacts scenes of fighting. The child-centered play therapist's appropriate response is:", options: ["Remove aggressive toys from the playroom", "Allow the therapeutic play within safety limits, track the child's behavior ('You're making the soldiers fight'), reflect feelings ('They seem really angry'), and trust the child's innate capacity for self-healing through play", "Interpret the play as evidence of abuse", "Redirect the child to calmer activities"], correctIndex: 1, rationale: "In child-centered play therapy (Axline, Landreth), the therapist follows the child's lead and trusts the child's therapeutic direction. Aggressive play is common and serves important functions: expressing emotions safely, gaining mastery, processing experiences, and developing coping skills. The therapist tracks behavior, reflects feelings, sets limits only when needed for safety, and avoids premature interpretation. Removing aggressive toys or redirecting denies the child access to a crucial mode of expression.", difficulty: 3, category: "Child & Family Services", topic: "Play Therapy", questionType: "CASE_VIGNETTE" },
  { id: "sw-1414", stem: "In the context of suicide prevention, 'means restriction' refers to:", options: ["Restricting client freedoms during hospitalization", "Reducing access to lethal methods of suicide, such as firearms, medications, or other means, which is one of the most effective evidence-based strategies for preventing suicide deaths", "Limiting financial resources", "Restricting social media access"], correctIndex: 1, rationale: "Means restriction is one of the most strongly supported suicide prevention strategies. Research shows that many suicidal crises are time-limited, and if access to lethal means is reduced during the crisis period, many people will not substitute another method. Specific strategies include: safe storage of firearms, medication lock boxes, bridge barriers, and counseling on access to lethal means (CALM). Social workers play a key role in discussing means restriction with at-risk clients and their families.", difficulty: 2, category: "Crisis Intervention", topic: "Suicide Risk", questionType: "MCQ" },
  { id: "sw-1415", stem: "A social worker is facilitating a support group for immigrant women. Several members express distrust of the social worker because of past negative experiences with authority figures. The social worker should:", options: ["Take the distrust personally and become defensive", "Acknowledge the distrust as understandable given their experiences, demonstrate cultural humility, be transparent about the social worker's role and group confidentiality, and consistently follow through on commitments to build trust over time", "Require members to trust before participating", "Avoid discussing the distrust to keep the group comfortable"], correctIndex: 1, rationale: "Distrust of authority figures is a common and understandable response for immigrants who may have experienced government persecution, exploitation, or broken promises. The social worker should validate this distrust, demonstrate cultural humility (acknowledging limitations in understanding their experiences), provide clear information about confidentiality and the social worker's role, and build trust through consistent, transparent, reliable behavior over time. Trust is earned, not demanded.", difficulty: 3, category: "Diversity, Equity & Inclusion", topic: "Immigration Social Work", questionType: "CASE_VIGNETTE" },
  { id: "sw-1416", stem: "DBT's 'chain analysis' is used to:", options: ["Track hereditary mental illness", "Examine the sequence of events, thoughts, emotions, and behaviors that led to a problematic behavior, identifying vulnerability factors, prompting events, links in the chain, and consequences to develop targeted intervention strategies", "Analyze family dynamics", "Create treatment timelines"], correctIndex: 1, rationale: "Chain analysis is a core DBT behavioral analysis tool that traces the detailed sequence leading to a target behavior. Components: vulnerability factors (what made the person susceptible), prompting event (what started the chain), links (thoughts, emotions, body sensations, actions between prompt and target behavior), target behavior (the problematic action), and consequences (short and long-term). This detailed analysis identifies where different skills could have been applied to change the outcome and prevents future occurrences.", difficulty: 3, category: "Clinical Practice", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1417", stem: "A social worker at a community mental health center is asked to provide services to a client who is a close friend of the social worker's family member. The most ethical response is:", options: ["Provide services since the client needs help", "Recognize the dual relationship, explain the ethical conflict to the client, and provide an appropriate referral to another qualified professional while ensuring continuity of care", "Ask the family member for permission to treat the client", "Provide services but do not document them"], correctIndex: 1, rationale: "The NASW Code of Ethics prohibits dual relationships that could exploit or harm clients. A pre-existing social connection through a family member creates a dual relationship that could compromise objectivity, confidentiality, and professional boundaries. The ethical response is to acknowledge the conflict, explain it to the client without disclosing unnecessary details, and provide a referral to an equally qualified professional. The social worker should ensure a smooth transition to prevent gaps in care.", difficulty: 2, category: "Ethics & Professional Boundaries", topic: "DBT", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1418", stem: "What is the 'adaptive information processing' (AIP) model underlying EMDR therapy?", options: ["A computer-based data processing system", "A theoretical model proposing that the brain has an innate information processing system that naturally moves toward healing, but traumatic memories can become maladaptively stored in isolated neural networks, and EMDR facilitates reprocessing to integrate these memories into adaptive networks", "A model for processing insurance claims", "A cognitive behavioral framework"], correctIndex: 1, rationale: "The AIP model (Shapiro) proposes that the brain naturally processes experiences toward adaptive resolution. However, traumatic or overwhelming experiences can become maladaptively stored—frozen in their original disturbing form with the emotions, physical sensations, and beliefs intact. These unprocessed memories are the basis of pathology. EMDR's bilateral stimulation is thought to activate the brain's inherent processing system, allowing the maladaptive memory to be integrated with existing adaptive networks, reducing disturbance and updating negative cognitions.", difficulty: 4, category: "Trauma-Informed Care", topic: "EMDR", questionType: "MCQ" },
  { id: "sw-1419", stem: "A social worker is developing a self-care plan. Which component is MOST often neglected by helping professionals?", options: ["Physical exercise", "Professional self-care activities such as regular clinical supervision, maintaining professional boundaries, attending to caseload management, and processing difficult cases with peers rather than carrying them alone", "Social activities", "Adequate sleep"], correctIndex: 1, rationale: "While personal self-care (exercise, sleep, social activities) is important, professional self-care is frequently overlooked. This includes: regular clinical supervision, manageable caseloads, debriefing difficult cases, maintaining boundaries between work and personal life, continuing education, advocating for organizational support, taking vacation time, and setting limits on availability. Many social workers focus on personal wellness while neglecting systemic and professional factors that contribute most significantly to burnout and compassion fatigue.", difficulty: 3, category: "Ethics & Professional Boundaries", topic: "Self-Care for Social Workers", questionType: "MCQ" },
  { id: "sw-1420", stem: "In ACT, 'experiential avoidance' is defined as:", options: ["Avoiding new experiences", "The unwillingness to remain in contact with uncomfortable internal experiences (thoughts, feelings, sensations, memories) and the attempts to alter, control, or eliminate these experiences, even when doing so creates long-term harm", "Avoiding social situations", "A healthy coping mechanism"], correctIndex: 1, rationale: "Experiential avoidance is a central concept in ACT and is considered a core pathological process. It involves trying to escape, avoid, or suppress unwanted internal experiences. Examples include substance use to numb emotions, social withdrawal to avoid anxiety, and thought suppression to avoid painful memories. While avoidance may provide short-term relief, it paradoxically increases suffering and prevents valued living. ACT promotes acceptance and willingness as alternatives to experiential avoidance.", difficulty: 2, category: "Clinical Practice", topic: "ACT", questionType: "MCQ" },
  { id: "sw-1421", stem: "A crisis social worker receives a call from a client who says, 'I've decided to end it tonight. I have my plan.' What is the immediate priority?", options: ["Schedule an appointment for the next day", "Maintain the client on the line, assess for immediate safety (location, means, lethality, alone or with others), activate emergency services if needed, and do not leave the client unsupported until safety is established", "Ask the client to call back during business hours", "Refer the client to the suicide prevention hotline"], correctIndex: 1, rationale: "This represents an imminent suicide crisis requiring immediate action. The social worker should: keep the client on the line (do not hang up), remain calm and empathetic, assess immediate risk factors (plan specifics, means access, location, alone or with others, substance use), activate emergency services (911) using another line or colleague, attempt to engage the client in safety strategies, and not leave the client unsupported until emergency services arrive or safety is established. This is a life-threatening emergency.", difficulty: 4, category: "Crisis Intervention", topic: "Suicide Risk", questionType: "PRIORITIZATION" },
  { id: "sw-1422", stem: "What is the role of 'homework' in DBT skills training?", options: ["Punishment for non-compliance", "Skills practice assignments that help clients generalize new skills from the group setting to their daily lives, with diary cards used to track skill use, emotions, and target behaviors between sessions", "Optional reading materials", "Academic exercises unrelated to therapy"], correctIndex: 1, rationale: "DBT homework serves to bridge the gap between skills group learning and real-life application. Diary cards are the primary homework tool—clients track daily emotions, urges, target behaviors, and skill use. Skills practice assignments apply specific learned skills to real-life situations. Homework review at the beginning of each group session reinforces practice, identifies barriers, and provides opportunities for troubleshooting. Non-completion is addressed with behavioral analysis rather than punishment.", difficulty: 2, category: "Clinical Practice", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1423", stem: "A domestic violence survivor has returned to the abuser three times. The social worker should:", options: ["Refuse to provide further services", "Recognize that leaving an abusive relationship is a process that often involves multiple attempts, continue to provide non-judgmental support, maintain the therapeutic relationship, update the safety plan, and respect the client's autonomy while ensuring they have information about resources", "Tell the client they must leave the relationship", "Discharge the client for non-compliance"], correctIndex: 1, rationale: "Research shows that domestic violence survivors leave an average of 7-8 times before permanently separating. Each return does not represent failure—it reflects the complex dynamics of power, control, trauma bonding, financial dependence, concern for children, and legitimate safety fears. The social worker maintains a non-judgmental stance, continues to provide support, updates safety plans, validates the client's experience, and trusts the client's timeline while ensuring they have information and resources when ready.", difficulty: 3, category: "Crisis Intervention", topic: "Domestic Violence", questionType: "APPLIED_ETHICS" },
  { id: "sw-1424", stem: "Which sampling method is most susceptible to researcher bias in social work research?", options: ["Simple random sampling", "Convenience sampling, where participants are selected based on easy availability rather than systematic criteria, potentially producing a sample that is not representative of the target population", "Stratified random sampling", "Systematic random sampling"], correctIndex: 1, rationale: "Convenience sampling selects participants based on availability and willingness rather than systematic random selection. This introduces selection bias because the sample may not represent the broader population—those who are accessible and willing may differ systematically from those who are not. While commonly used in social work research due to practical constraints, researchers must acknowledge its limitations regarding generalizability and interpret findings accordingly.", difficulty: 2, category: "Assessment & Intervention Planning", topic: "Research Methods", questionType: "MCQ" },
  { id: "sw-1425", stem: "A social worker providing EMDR to a combat veteran notices the client consistently avoids discussing a particular deployment event. The therapist should:", options: ["Force the client to discuss the event", "Assess whether the client has adequate preparation and stabilization resources, explore the avoidance with curiosity and without judgment, and respect the client's pacing while gently addressing the avoidance as a potential barrier to processing", "Ignore the avoidance and process other memories", "Terminate EMDR and switch to another modality"], correctIndex: 1, rationale: "Avoidance is a hallmark of PTSD and should be addressed therapeutically rather than ignored or forced. The EMDR therapist assesses readiness (Phase 2 preparation), explores the avoidance with the client (what makes this memory feel different?), ensures adequate coping resources, and collaborates on a treatment plan that respects pacing while addressing the avoidance. The avoided memory may be the core target, and premature processing without adequate preparation could destabilize the client.", difficulty: 4, category: "Trauma-Informed Care", topic: "EMDR", questionType: "CASE_VIGNETTE" },
  { id: "sw-1426", stem: "What is the primary purpose of the 'norming' stage in group development?", options: ["Establishing group rules at the first meeting", "Developing group cohesion, trust, and shared expectations after resolving the conflicts of the storming stage, where members begin to appreciate differences and work collaboratively toward group goals", "Conducting intake assessments", "Evaluating group outcomes"], correctIndex: 1, rationale: "Tuckman's norming stage follows storming and is characterized by increasing cohesion, mutual respect, and cooperation. Members develop shared norms and expectations, appreciate individual differences, feel a sense of belonging, and begin working collaboratively. The facilitator supports this by reinforcing positive interactions, highlighting commonalities, encouraging mutual support, and gradually shifting leadership responsibilities to the group. Norming sets the stage for the performing phase where productive therapeutic work occurs.", difficulty: 2, category: "Clinical Practice", topic: "Group Dynamics", questionType: "MCQ" },
  { id: "sw-1427", stem: "A social worker assessing an immigrant client discovers the client was tortured in their country of origin. The most important trauma-informed consideration is:", options: ["Immediately processing the torture memories in detail", "Establishing safety and trust first, recognizing that authority figures may be triggering, allowing the client to share at their own pace, and connecting them with specialized torture treatment services", "Requiring a detailed written account of the torture", "Focusing only on current functioning without acknowledging the trauma"], correctIndex: 1, rationale: "Survivors of torture require specialized trauma-informed care. Key considerations: safety and trust are paramount (torture survivors were harmed by authority figures, making therapeutic relationships potentially triggering), the client controls the pace of disclosure, the social worker avoids replicating power dynamics reminiscent of torture (coercion, control, invasive questioning), and referral to specialized torture treatment programs (which exist in many cities) is appropriate. Medical, legal, and mental health needs should be addressed in an integrated, culturally responsive manner.", difficulty: 4, category: "Trauma-Informed Care", topic: "Immigration Social Work", questionType: "CASE_VIGNETTE" },
  { id: "sw-1428", stem: "What is 'motivational interviewing' (MI) and when is it most appropriate?", options: ["Interviewing for job motivation", "A collaborative, person-centered counseling approach that helps clients explore and resolve ambivalence about behavior change by evoking their own motivations and building their confidence to change, most appropriate when clients are ambivalent rather than resistant", "Confrontational interviewing about substance use", "A screening tool for motivation levels"], correctIndex: 1, rationale: "MI (Miller & Rollnick) is a collaborative approach for strengthening intrinsic motivation. Core principles: express empathy, develop discrepancy, roll with resistance, and support self-efficacy. Key skills: OARS (Open questions, Affirmations, Reflections, Summaries). MI is most effective when clients are ambivalent—they have reasons both for and against change. The spirit of MI involves partnership, acceptance, compassion, and evocation. It is not appropriate when clients have already decided to change or when immediate safety requires directive action.", difficulty: 1, category: "Addictions & Substance Use", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1429", stem: "A social worker notices increasing cynicism, detachment from clients, and a sense that their work doesn't matter. The MOST important first step is:", options: ["Resign from the position immediately", "Engage in honest self-reflection and seek consultation with a supervisor or trusted colleague to assess the severity of burnout and develop a plan that addresses both personal self-care and organizational factors", "Increase caseload to stay busy", "Ignore the feelings and push through"], correctIndex: 1, rationale: "The first step in addressing burnout is self-awareness and honest reflection. Seeking supervision or peer consultation allows for objective assessment of the situation and collaborative problem-solving. The plan should address both individual factors (self-care practices, boundary setting, personal therapy) and organizational factors (caseload, supervision quality, workplace culture). Ignoring burnout worsens symptoms and compromises client care. Early intervention is more effective than waiting until crisis.", difficulty: 2, category: "Ethics & Professional Boundaries", topic: "Burnout Prevention", questionType: "PRIORITIZATION" },
  { id: "sw-1430", stem: "In ACT, the concept of 'self-as-context' refers to:", options: ["The client's self-concept or self-esteem", "An awareness of oneself as the observer of one's experiences—a stable perspective from which thoughts, feelings, and sensations can be noticed without being defined by them, creating psychological space for flexibility", "The client's social context", "Self-assessment questionnaires"], correctIndex: 1, rationale: "Self-as-context (or the observing self) is one of ACT's six core processes. It involves experiencing oneself as the context in which thoughts, feelings, and sensations occur rather than being defined by their content. Unlike the conceptualized self ('I am a failure'), the observing self provides a stable vantage point: 'I notice the thought that I am a failure.' This creates psychological distance and flexibility. Metaphors include the sky (self-as-context) and weather (changing thoughts and feelings).", difficulty: 4, category: "Clinical Practice", topic: "ACT", questionType: "MCQ" },
  { id: "sw-1431", stem: "A social worker is developing a rapid rehousing program for families experiencing homelessness. Which components are essential?", options: ["Long-term residential treatment", "Short-term rental assistance with progressive reduction, housing search and landlord negotiation support, case management services, connection to community resources, and follow-up to prevent return to homelessness", "Permanent subsidized housing only", "Emergency shelter with unlimited stays"], correctIndex: 1, rationale: "Rapid rehousing is an evidence-based intervention that moves families quickly from homelessness to permanent housing. Essential components include: housing identification (locating units, landlord engagement), short-term financial assistance (rental subsidies that decrease over time), case management (connecting to employment, benefits, childcare, healthcare), and follow-up (monitoring housing stability and addressing emerging needs). It differs from Housing First (for chronic homelessness) in its time-limited assistance model targeting families who need temporary support.", difficulty: 3, category: "Clinical Practice", topic: "Homelessness Interventions", questionType: "PRIORITIZATION" },
  { id: "sw-1432", stem: "What is the role of 'bilateral stimulation' in EMDR therapy?", options: ["It distracts the client from their problems", "It is hypothesized to facilitate the processing of traumatic memories by engaging both hemispheres of the brain, potentially through mechanisms similar to REM sleep, allowing the memory to be adaptively integrated and its emotional charge reduced", "It is a relaxation technique only", "It replaces the need for a therapeutic relationship"], correctIndex: 1, rationale: "Bilateral stimulation (BLS) in EMDR involves alternating left-right sensory input through eye movements, taps, or auditory tones. While the exact mechanism is debated, hypotheses include: dual attention (simultaneously holding past memory and present awareness), working memory taxation (reducing vividness and emotionality of the memory), and REM-like processing (facilitating memory consolidation). Research supports that BLS adds therapeutic benefit beyond exposure alone, though the therapeutic relationship remains essential.", difficulty: 3, category: "Trauma-Informed Care", topic: "EMDR", questionType: "MCQ" },
  { id: "sw-1433", stem: "A social worker is conducting a lethality assessment with a domestic violence victim who has just been strangled by the partner. What does strangulation indicate about risk?", options: ["It is a minor assault with no prognostic significance", "Strangulation is one of the most significant predictors of future homicide in intimate partner violence, indicating an extremely high-risk situation that requires immediate safety planning and potentially emergency intervention", "It only indicates emotional abuse", "It is relevant only if visible injuries are present"], correctIndex: 1, rationale: "Research consistently shows that prior strangulation by an intimate partner increases the risk of future homicide by 750%. Strangulation is a uniquely lethal form of violence—it can cause death with minimal force and often leaves few visible marks. Assessment should include: medical evaluation (delayed complications can occur), immediate safety planning, documentation, connection to domestic violence advocacy, consideration of emergency protection orders, and assessment for traumatic brain injury. This is a critical risk factor in lethality assessments.", difficulty: 5, category: "Crisis Intervention", topic: "Domestic Violence", questionType: "CASE_VIGNETTE" },
  { id: "sw-1434", stem: "What type of validity ensures that a research instrument measures what it is intended to measure?", options: ["External validity", "Construct validity, which assesses whether the instrument accurately captures the theoretical concept it claims to measure through convergent and discriminant evidence", "Internal validity", "Statistical validity"], correctIndex: 1, rationale: "Construct validity examines whether an instrument truly measures the abstract concept (construct) it is intended to measure. It includes convergent validity (the instrument correlates with other measures of the same construct) and discriminant validity (the instrument does not correlate with measures of unrelated constructs). Other types—content validity (covers the domain), criterion validity (predicts outcomes), and face validity (appears to measure what it should)—contribute to overall validity assessment.", difficulty: 3, category: "Assessment & Intervention Planning", topic: "Research Methods", questionType: "MCQ" },
  { id: "sw-1435", stem: "In Piaget's theory of cognitive development, a 7-year-old child is likely in which stage?", options: ["Sensorimotor stage", "Concrete operational stage, where the child can think logically about concrete events, understand conservation, classification, and seriation, but has difficulty with abstract or hypothetical reasoning", "Formal operational stage", "Preoperational stage"], correctIndex: 1, rationale: "Piaget's concrete operational stage (approximately ages 7-11) is characterized by: logical thinking about concrete objects and events, understanding conservation (quantity doesn't change with appearance), classification (grouping by shared characteristics), seriation (ordering by size), and reversibility (mental undoing of actions). Children at this stage struggle with abstract, hypothetical, or purely logical reasoning, which develops in the formal operational stage (age 11+).", difficulty: 1, category: "Human Development", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1436", stem: "A social worker in a school setting notices a student who was previously outgoing has become withdrawn, is giving away possessions, and wrote a poem about death. The MOST appropriate immediate action is:", options: ["Wait to see if the behavior changes on its own", "Conduct a direct suicide risk assessment with the student by asking clear, compassionate questions about suicidal thoughts, plans, and intent, and follow the school's crisis protocol", "Call the parents first without talking to the student", "Refer the student to the school counselor for a routine appointment"], correctIndex: 1, rationale: "The student is displaying multiple warning signs for suicide: personality change, withdrawal, giving away possessions, and death-themed communication. These warrant an immediate, direct suicide risk assessment. Asking directly about suicidal thoughts does not increase risk—it opens a door for the student to seek help. The social worker should use clear, compassionate language, assess ideation, plan, means, and intent, follow the school's crisis protocol, ensure the student is not left alone, and notify parents/guardians per protocol.", difficulty: 2, category: "Crisis Intervention", topic: "Suicide Risk", questionType: "PRIORITIZATION" },
  { id: "sw-1437", stem: "Which of the following best describes the 'wise mind' concept in DBT?", options: ["Being rational and ignoring emotions", "The synthesis of emotional mind (driven by feelings) and reasonable mind (driven by logic), representing an intuitive knowing that integrates both emotion and reason to guide effective decision-making", "Only trusting gut instincts", "A state achieved only through meditation"], correctIndex: 1, rationale: "Wise mind is a core DBT mindfulness concept representing the integration of emotional mind (reactive, mood-dependent, driven by feelings) and reasonable mind (logical, task-focused, cool). Wise mind includes both emotional and rational elements, adding intuitive wisdom. It is accessed through mindfulness practices and is characterized by a sense of 'knowing' that feels right. All people possess wise mind; the skill is learning to access and trust it, especially during emotional crises.", difficulty: 1, category: "Clinical Practice", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1438", stem: "A social worker receives an immigrant client who has been granted asylum. What psychosocial challenges might the client face post-asylum?", options: ["All problems end once asylum is granted", "Ongoing challenges including PTSD from pre-migration trauma, grief and loss, acculturation stress, language barriers, employment difficulties, social isolation, survivor guilt, and navigating complex immigration systems for family reunification", "Only language barriers", "Only employment concerns"], correctIndex: 1, rationale: "Post-asylum psychosocial challenges are complex and multifaceted: mental health effects of pre-migration trauma (war, persecution, torture), migration journey trauma (dangerous crossings, detention), post-migration stressors (acculturation, discrimination, language barriers), grief for lost homeland, family, and identity, survivor guilt, employment challenges (credential recognition, discrimination), social isolation, navigating healthcare and social service systems, and the lengthy process of family reunification. Asylum resolves legal status but not the underlying psychosocial impacts.", difficulty: 3, category: "Diversity, Equity & Inclusion", topic: "Immigration Social Work", questionType: "CASE_VIGNETTE" },
  { id: "sw-1439", stem: "In group therapy, 'universality' as a therapeutic factor (Yalom) refers to:", options: ["Using universal treatment protocols", "The realization by group members that they are not alone in their experiences and that others share similar problems, feelings, and concerns, which reduces isolation and shame", "Applying one theoretical model to all groups", "Ensuring all members have the same diagnosis"], correctIndex: 1, rationale: "Universality is one of Yalom's eleven therapeutic factors in group therapy. When members discover that others share similar struggles, feelings, and experiences, they experience relief from the isolation and shame of believing their problems are unique. This realization normalizes their experience and fosters connection. Universality is especially powerful in early group stages and for conditions associated with high stigma (addiction, mental illness, trauma). The facilitator can enhance universality by drawing connections between members' shared experiences.", difficulty: 1, category: "Clinical Practice", topic: "Group Dynamics", questionType: "MCQ" },
  { id: "sw-1440", stem: "A social worker is debating whether to use a standardized outcome measure or a qualitative interview to assess treatment progress. The best approach would be:", options: ["Only use standardized measures", "Use a mixed-methods approach that combines standardized outcome measures for quantifiable data with qualitative interviews for rich contextual understanding of the client's experience of change", "Only use qualitative interviews", "Avoid assessment altogether and rely on clinical judgment alone"], correctIndex: 1, rationale: "Mixed-methods approaches combine the strengths of both quantitative and qualitative methods. Standardized measures provide reliable, comparable data on symptom reduction and functional improvement. Qualitative methods capture the client's subjective experience, contextual factors, and nuanced changes that standardized measures may miss. Together, they provide a comprehensive picture of treatment progress. This approach aligns with evidence-based practice's integration of research evidence, clinical expertise, and client perspectives.", difficulty: 3, category: "Assessment & Intervention Planning", topic: "Research Methods", questionType: "MCQ" },
  { id: "sw-1441", stem: "Which of the following is an example of a 'committed action' in ACT?", options: ["Waiting until anxiety decreases before taking action", "Taking a concrete, values-consistent step even while experiencing difficult thoughts and feelings, such as attending a job interview despite anxiety about rejection", "Avoiding situations that trigger discomfort", "Making plans but not following through"], correctIndex: 1, rationale: "Committed action in ACT involves taking concrete behavioral steps guided by values, regardless of internal discomfort. It is not about waiting for difficult feelings to pass or trying to feel better before acting. Instead, it involves willingness to experience whatever shows up internally while moving toward what matters. Committed action is ongoing and flexible—when barriers arise, the person recommits to their values and adjusts their approach. It is the behavioral outcome of ACT's six core processes.", difficulty: 2, category: "Clinical Practice", topic: "ACT", questionType: "MCQ" },
  { id: "sw-1442", stem: "A social worker discovers that a homeless shelter they work at has policies that effectively exclude transgender individuals. The most ethical action is:", options: ["Accept the policies as organizational decisions", "Advocate within the organization for inclusive, affirming policies that comply with nondiscrimination standards, educate staff on transgender-inclusive practices, and connect excluded individuals with affirming services while working toward systemic change", "Quietly refer transgender clients elsewhere", "Resign in protest"], correctIndex: 1, rationale: "The NASW Code of Ethics requires social workers to challenge social injustice and advocate for vulnerable populations. Transgender individuals experience homelessness at disproportionately high rates and face discrimination in shelter systems. The social worker should: advocate internally for policy change, educate staff on transgender-inclusive practices, connect clients with affirming services in the interim, document the discriminatory impact, and if needed, escalate concerns through appropriate channels. Systemic advocacy is an ethical obligation, not optional.", difficulty: 4, category: "Ethics & Professional Boundaries", topic: "Homelessness Interventions", questionType: "APPLIED_ETHICS" },
  { id: "sw-1443", stem: "What is the 'window of tolerance' concept in trauma-informed care?", options: ["How much stress a workplace can handle", "The optimal zone of arousal in which a person can effectively process information and function adaptively, with hyperarousal (fight/flight) and hypoarousal (freeze/collapse) existing outside this window", "A time limit for therapy sessions", "The amount of trauma a person can endure"], correctIndex: 1, rationale: "The window of tolerance (Siegel) describes the optimal zone of autonomic arousal. Within this window, a person can think clearly, experience emotions without being overwhelmed, and function adaptively. Above the window is hyperarousal (anxiety, panic, anger, hypervigilance). Below is hypoarousal (numbness, dissociation, collapse, shutdown). Trauma narrows the window of tolerance. Therapy aims to: widen the window through skills and processing, help clients recognize when they're outside the window, and use strategies to return to the window.", difficulty: 2, category: "Trauma-Informed Care", topic: "EMDR", questionType: "MCQ" },
  { id: "sw-1444", stem: "A social worker leading a process group notices that members consistently avoid discussing a particular topic that is clearly relevant to the group's purpose. This is an example of:", options: ["Effective boundary setting by the group", "Group resistance or avoidance, which the facilitator should address by naming the observed pattern, exploring what makes the topic difficult, and creating safety for the group to engage with the avoided material", "The group's natural pace", "Poor group facilitation"], correctIndex: 1, rationale: "Group-level avoidance of relevant topics signals resistance that, if unaddressed, limits therapeutic progress. The facilitator should process the avoidance as a group phenomenon: 'I've noticed we haven't talked about X. I'm curious about what that's like for the group.' This intervention invites meta-communication about the avoidance, normalizes the difficulty, and creates space for exploration. Understanding the function of avoidance (protection from vulnerability, fear of judgment, unresolved conflict) guides further facilitation.", difficulty: 4, category: "Clinical Practice", topic: "Group Dynamics", questionType: "CASE_VIGNETTE" },
  { id: "sw-1445", stem: "The Stanley-Brown Safety Planning Intervention for suicide prevention includes which elements?", options: ["Only a list of emergency phone numbers", "Six steps: recognizing warning signs, using internal coping strategies, accessing social contacts for distraction, contacting family or friends for help, contacting professionals and crisis services, and reducing access to lethal means", "A contract promising not to attempt suicide", "A risk assessment tool only"], correctIndex: 1, rationale: "The Stanley-Brown Safety Planning Intervention is an evidence-based, brief intervention that creates a prioritized written list of coping strategies and resources: (1) warning signs that a crisis may be developing, (2) internal coping strategies the person can use independently, (3) people and social settings for distraction, (4) people who can provide help, (5) professionals and agencies to contact during crisis, (6) steps to make the environment safer (means restriction). It is collaborative, portable, and replaces the outdated 'no-suicide contract.'", difficulty: 3, category: "Crisis Intervention", topic: "Suicide Risk", questionType: "MCQ" },
  { id: "sw-1446", stem: "A social worker is working with a child who uses sand tray therapy to create a scene with a 'monster' hiding behind a house. In Jungian sand tray therapy, the therapist should:", options: ["Remove the monster figure", "Witness the scene without interpretation, hold the therapeutic space with acceptance, and allow the symbolic process to unfold at the child's pace, understanding that the sand tray scene represents the child's inner world", "Ask the child what the monster represents in real life", "Correct the scene to show the monster being defeated"], correctIndex: 1, rationale: "In Jungian sand tray therapy, the therapist serves as a witness and holder of the therapeutic space. The process is largely nonverbal and symbolic. The therapist avoids interpreting or directing the scene, instead trusting the client's unconscious process. The sand tray provides a contained, tangible medium for expressing internal experiences that may be beyond verbal expression. The therapist's silent, accepting presence creates safety for the unconscious to express and resolve psychological material through symbolic play.", difficulty: 4, category: "Child & Family Services", topic: "Play Therapy", questionType: "CASE_VIGNETTE" },
  { id: "sw-1447", stem: "Which ethical principle is MOST relevant when a social worker must decide between respecting a client's autonomy and protecting them from harm?", options: ["Beneficence only", "The tension between self-determination and duty to protect, requiring the social worker to balance respect for the client's right to make their own decisions with the professional obligation to prevent serious, foreseeable harm", "Confidentiality only", "Justice only"], correctIndex: 1, rationale: "The ethical tension between self-determination (client autonomy) and duty to protect (preventing harm) is one of the most challenging in social work practice. The social worker must weigh: the severity and imminence of the potential harm, the client's capacity for autonomous decision-making, the least restrictive intervention available, legal mandates (mandatory reporting, duty to warn), and professional ethical guidelines. This balancing act requires careful judgment, consultation, and documentation of the decision-making process.", difficulty: 3, category: "Ethics & Professional Boundaries", topic: "Self-Care for Social Workers", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1448", stem: "In DBT, the 'opposite action' skill is used when:", options: ["The client needs to express more emotion", "The emotion does not fit the facts of the situation or when acting on the emotion would be ineffective, prompting the client to act opposite to the emotion's action urge to change the emotional experience", "The client wants to try something new", "The therapist disagrees with the client's emotions"], correctIndex: 1, rationale: "Opposite action is a DBT emotion regulation skill used when an emotion is unjustified by the situation or when acting on the emotion would be harmful. The principle: emotions have action urges (fear urges avoidance, sadness urges withdrawal, anger urges attack). Opposite action involves acting contrary to the urge (approaching what is feared, activating when sad, being gentle when angry). The key is 'all the way'—fully committing to the opposite behavior, including changing facial expression and body posture. This skill can change the emotional experience.", difficulty: 3, category: "Clinical Practice", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1449", stem: "A social worker conducting research on the effectiveness of a substance use treatment program should address which potential ethical concern?", options: ["There are no ethical concerns in treatment research", "The ethical concern of withholding effective treatment from a control group, which can be addressed through waitlist controls, standard care comparisons, or providing all participants access to the treatment after the study period", "Only obtaining IRB approval is sufficient", "Only concerns about data collection methods"], correctIndex: 1, rationale: "Research ethics in treatment studies include: informed consent (voluntary, comprehensive, ongoing), withholding treatment (using waitlist or treatment-as-usual controls rather than no-treatment controls), confidentiality of sensitive substance use data, dual role of clinician-researcher, vulnerable population protections, data security (especially with illegal substance use data), and Certificate of Confidentiality protections. The equipoise principle—genuine uncertainty about which treatment is better—justifies randomization.", difficulty: 4, category: "Assessment & Intervention Planning", topic: "Research Methods", questionType: "APPLIED_ETHICS" },
  { id: "sw-1450", stem: "What is Kohlberg's 'conventional' level of moral development?", options: ["Following rules only to avoid punishment", "A level where moral reasoning is based on conforming to social expectations, maintaining relationships, and upholding social order, typically developing in adolescence and continuing through adulthood for many people", "Making moral decisions based on universal principles", "Moral reasoning based entirely on self-interest"], correctIndex: 1, rationale: "Kohlberg's conventional level (Stages 3-4) is characterized by: Stage 3 (good boy/nice girl orientation—conforming to social expectations, seeking approval, and valuing relationships) and Stage 4 (law and order orientation—following rules, respecting authority, maintaining social order). This level develops in adolescence and many adults reason primarily at this level. It follows the preconventional level (self-interest) and precedes the postconventional level (universal principles). Understanding moral development stages helps social workers tailor interventions.", difficulty: 2, category: "Human Development", topic: "ACT", questionType: "MCQ" },
  { id: "sw-1451", stem: "A social worker providing crisis intervention to a survivor of a mass shooting should prioritize:", options: ["Debriefing the event in detail immediately", "Ensuring physical safety, providing psychological first aid (calm, orient, connect, stabilize), assessing immediate needs, connecting to support systems, and avoiding premature processing of the traumatic event", "Administering psychological assessments", "Prescribing medication for anxiety"], correctIndex: 1, rationale: "Crisis intervention following mass violence prioritizes: physical safety, basic needs, and psychological first aid (PFA). PFA principles include: contact and engagement, safety and comfort, stabilization (calming overwhelmed survivors), information gathering (current needs and concerns), practical assistance, connection with social supports, information on coping, and linkage to collaborative services. Critical incident stress debriefing (CISD) is not recommended immediately after trauma as it can worsen outcomes. Processing should occur when the survivor is stabilized.", difficulty: 3, category: "Crisis Intervention", topic: "Crisis Assessment", questionType: "PRIORITIZATION" },
  { id: "sw-1452", stem: "A social worker is implementing a psychoeducation group for parents of children with ADHD. Which group format is most appropriate?", options: ["An unstructured process group", "A structured educational group with a planned curriculum covering ADHD knowledge, behavioral management strategies, advocacy skills, and peer support, incorporating evidence-based content with opportunities for discussion and practice", "Individual parent coaching only", "A confrontational group to address parenting deficits"], correctIndex: 1, rationale: "Psychoeducation groups for parents combine education with peer support. Key components: information about ADHD (neurobiology, symptoms, course), behavioral management strategies (positive reinforcement, consistent structure, effective commands), school advocacy skills (IEP/504 plans), stress management for parents, and mutual support among parents sharing similar challenges. A structured curriculum ensures evidence-based content is covered while allowing space for discussion, questions, and peer connection. This format empowers parents with knowledge and skills.", difficulty: 2, category: "Child & Family Services", topic: "Group Dynamics", questionType: "MCQ" },
  { id: "sw-1453", stem: "In ACT, 'present moment awareness' (contact with the present moment) involves:", options: ["Constant meditation practice", "Flexibly attending to current experience with openness and curiosity rather than being caught up in rumination about the past or worry about the future, allowing for more effective engagement with life", "Never thinking about the past or future", "Mindfulness as relaxation only"], correctIndex: 1, rationale: "Contact with the present moment in ACT involves flexible, voluntary, non-judgmental attention to what is happening right now—both internally and externally. It is not about rigid present-focus or constant meditation, but about the ability to bring attention back to the present when it wanders to rumination or worry. Present moment awareness allows clients to notice their experience without being controlled by it, make conscious choices aligned with values, and engage fully in their lives.", difficulty: 2, category: "Clinical Practice", topic: "ACT", questionType: "MCQ" },
  { id: "sw-1454", stem: "A social worker has been working with the same client for two years and notices growing dependency in the therapeutic relationship. What should the social worker do?", options: ["Continue as usual since the client is comfortable", "Address the dependency therapeutically by exploring it openly with the client, gradually fostering autonomy and self-efficacy, consulting with a supervisor about the dynamic, and developing a plan for appropriate termination or transition", "Terminate immediately to end the dependency", "Increase session frequency to meet the client's needs"], correctIndex: 1, rationale: "Therapeutic dependency can indicate: unresolved attachment issues, the social worker inadvertently reinforcing dependency, or an overly long treatment without clear goals. The social worker should: explore the dependency in supervision, discuss it openly with the client (what does the relationship mean to them?), gradually build the client's independent coping skills and support systems, set clear treatment goals with a termination timeline, and ensure the client feels empowered rather than abandoned. Abrupt termination can be harmful.", difficulty: 3, category: "Ethics & Professional Boundaries", topic: "Burnout Prevention", questionType: "CASE_VIGNETTE" },
  { id: "sw-1455", stem: "What is the difference between 'secondary traumatic stress' (STS) and 'compassion fatigue'?", options: ["They are completely unrelated concepts", "STS refers to PTSD-like symptoms that develop from indirect exposure to trauma through clients' narratives, while compassion fatigue is a broader concept encompassing both STS and burnout, representing the overall cost of caring for traumatized populations", "STS is more severe than compassion fatigue", "Compassion fatigue only affects new social workers"], correctIndex: 1, rationale: "Secondary traumatic stress (Figley) involves PTSD-like symptoms (intrusive thoughts, avoidance, hyperarousal) developing from hearing clients' trauma narratives. Compassion fatigue (Stamm) is a broader construct that combines STS with burnout. The Professional Quality of Life scale (ProQOL) measures three domains: compassion satisfaction (positive), burnout (negative), and secondary traumatic stress (negative). Understanding these distinctions helps social workers identify which aspect of their distress to address and select appropriate interventions.", difficulty: 4, category: "Ethics & Professional Boundaries", topic: "Self-Care for Social Workers", questionType: "MCQ" },
  { id: "sw-1456", stem: "A social worker is conducting EMDR with a client who has complex PTSD from childhood abuse. How does the treatment approach differ from single-incident trauma?", options: ["There is no difference in approach", "Complex PTSD typically requires an extended preparation phase focused on stabilization, resource development, and relationship building before trauma processing, and may involve multiple targets across different developmental periods with careful sequencing", "Only the number of sessions differs", "Complex PTSD cannot be treated with EMDR"], correctIndex: 1, rationale: "EMDR for complex PTSD differs from single-incident trauma treatment in several ways: extended Phase 2 preparation (developing robust self-regulation skills, internal resources, and a strong therapeutic alliance), careful target sequencing (identifying and ordering multiple traumatic memories chronologically or by theme), addressing attachment disruptions and developmental impacts, managing dissociative responses, potentially using modified protocols (fractionated processing), and longer overall treatment duration. The AIP model recognizes that early adverse experiences create pervasive maladaptive neural networks.", difficulty: 5, category: "Trauma-Informed Care", topic: "EMDR", questionType: "CASE_VIGNETTE" },
  { id: "sw-1457", stem: "What is 'fidelity' in the context of implementing evidence-based interventions?", options: ["Client loyalty to the therapist", "The degree to which an intervention is delivered as intended by its developers, including adherence to the protocol, competence of the provider, and dosage of the intervention, which impacts the validity of outcomes", "A measure of treatment duration", "The client's belief in the treatment"], correctIndex: 1, rationale: "Implementation fidelity has multiple dimensions: adherence (following the protocol as designed), competence (the skill level of the provider), dosage (the amount of intervention delivered), differentiation (the intervention is distinguishable from comparison conditions), and participant responsiveness (client engagement). High fidelity ensures that outcomes can be attributed to the intervention itself. Low fidelity may explain poor outcomes and limits the conclusions that can be drawn about the intervention's effectiveness.", difficulty: 3, category: "Assessment & Intervention Planning", topic: "Research Methods", questionType: "MCQ" },
  { id: "sw-1458", stem: "A social worker is providing services to a family experiencing homelessness in a motel. The two school-age children have missed significant school time. Under the McKinney-Vento Act, these children have:", options: ["No special educational rights", "The right to remain in their school of origin, receive transportation to school, immediate enrollment without typical documentation, and access to comparable services including special education and free meals", "Only the right to enroll in the closest school", "Rights only if they are in a shelter"], correctIndex: 1, rationale: "The McKinney-Vento Homeless Assistance Act provides educational rights for homeless children and youth, including those in motels: right to remain in school of origin or immediately enroll in a new school, transportation to school of origin, enrollment without typical documentation (immunization records, birth certificate, proof of residency), access to all programs and services (Title I, special education, gifted, free meals), and a designated liaison in each school district. Social workers play a key role in connecting families to these rights and advocating for their implementation.", difficulty: 2, category: "Child & Family Services", topic: "Homelessness Interventions", questionType: "MCQ" },
  { id: "sw-1459", stem: "In DBT, what is the function of 'phone coaching' between sessions?", options: ["Social conversation with the therapist", "Brief, focused calls that help clients apply DBT skills to real-life crisis situations in the moment, prevent the need for emergency services, and generalize skills learned in therapy to everyday situations", "Extended therapy sessions by phone", "Checking in on homework completion"], correctIndex: 1, rationale: "DBT phone coaching is a structured component serving several functions: helping clients apply skills in real-time crisis situations, generalizing skills from therapy to daily life, providing brief coaching (not full therapy sessions), and repairing therapeutic relationship ruptures. Rules include: call before engaging in target behaviors (not after), calls are brief and focused on skill use, and the therapist may be unavailable at times. Phone coaching bridges the gap between weekly sessions and real-life skill application.", difficulty: 2, category: "Clinical Practice", topic: "DBT", questionType: "MCQ" },
  { id: "sw-1460", stem: "A social worker is assessing a client for domestic violence but the client denies abuse despite visible injuries. What should the social worker do?", options: ["Accept the denial and move on", "Express concern about the injuries in a non-judgmental way, provide information about domestic violence resources, document observations, ensure the client knows how to reach help if needed, and respect the client's readiness while leaving the door open for future disclosure", "Confront the client about lying", "Report the suspected abuse to police without the client's consent"], correctIndex: 1, rationale: "Denial in domestic violence situations is common due to fear, shame, minimization, trauma bonding, and safety concerns. The social worker should: express concern non-judgmentally, validate the client's experience, provide information about resources and safety, document objective observations, respect the client's timeline for disclosure, avoid pressuring or forcing disclosure, and ensure the client knows how to access help when ready. Building trust creates conditions for future disclosure. Mandatory reporting laws vary by jurisdiction for adult domestic violence.", difficulty: 3, category: "Crisis Intervention", topic: "Domestic Violence", questionType: "CASE_VIGNETTE" },
  { id: "sw-1461", stem: "What is attachment theory's concept of the 'internal working model'?", options: ["A type of cognitive behavioral technique", "Mental representations of self and others formed through early attachment experiences that shape expectations about relationships, self-worth, and how one relates to others throughout the lifespan", "A workplace organizational model", "A medical model of mental health"], correctIndex: 1, rationale: "Internal working models (Bowlby) are cognitive-affective representations developed through early attachment experiences. They contain: a model of self (worthy or unworthy of care), a model of others (reliable or unreliable, safe or dangerous), and expectations about relationships (e.g., 'If I express needs, they will be met' or 'If I show vulnerability, I'll be rejected'). These models operate largely outside awareness and influence adult relationships, parenting, emotional regulation, and therapeutic relationships. They can be updated through corrective relational experiences.", difficulty: 3, category: "Human Development", topic: "Group Dynamics", questionType: "MCQ" },
  { id: "sw-1462", stem: "A social worker wants to study whether a new intervention reduces anxiety in LGBTQ+ youth. Which research design would provide the strongest evidence?", options: ["A case study of one client", "A randomized controlled trial (RCT) comparing the new intervention to treatment as usual, with pre- and post-measures of anxiety using validated instruments and adequate sample size from the target population", "An uncontrolled pre-post study", "A survey of client satisfaction"], correctIndex: 1, rationale: "The RCT is considered the gold standard for evaluating intervention effectiveness because: random assignment controls for confounding variables, a comparison group isolates the intervention's effect, pre-post measurement captures change, validated instruments ensure reliable measurement, and adequate sample size provides statistical power. For LGBTQ+ youth, additional considerations include: culturally appropriate measures, inclusive recruitment, safety protections, community input in design, and attention to intersectionality in the sample.", difficulty: 3, category: "Assessment & Intervention Planning", topic: "Research Methods", questionType: "MCQ" },
  { id: "sw-1463", stem: "In play therapy, 'limit setting' serves which therapeutic purpose?", options: ["Punishing misbehavior", "Providing safety and structure in the playroom by establishing boundaries that protect the child, therapist, and property while communicating that the child is accepted even when specific behaviors are not permitted", "Restricting all aggressive play", "Ending sessions early for rule violations"], correctIndex: 1, rationale: "Limit setting in play therapy (ACT model: Acknowledge the feeling, Communicate the limit, Target alternatives) provides necessary structure within the permissive therapeutic environment. Limits are set on behaviors that: harm the child or therapist, damage property beyond repair, or are socially unacceptable. The child's feelings and desires are always accepted—only specific behaviors are limited. This teaches the child that they can be accepted fully even when certain behaviors are not allowed, mirroring healthy boundaries.", difficulty: 2, category: "Child & Family Services", topic: "Play Therapy", questionType: "MCQ" },
  { id: "sw-1464", stem: "A social worker is experiencing secondary traumatic stress symptoms after working intensively with survivors of sexual assault. What organizational factors should be addressed?", options: ["The social worker should handle it privately", "Organizational support including manageable caseloads, regular clinical supervision, peer support structures, trauma-informed organizational culture, administrative acknowledgment of the emotional impact of the work, and access to employee assistance programs", "Only individual therapy for the social worker", "Transferring the social worker to a different department"], correctIndex: 1, rationale: "Secondary traumatic stress is an occupational hazard, not a personal failing—organizational responsibility is essential. Evidence-based organizational responses include: balanced caseloads (mixing trauma and non-trauma cases), regular clinical supervision with trauma-competent supervisors, peer support groups, trauma-informed organizational culture (acknowledging the impact of the work), training on self-care and STS, flexible scheduling, employee assistance programs, and leadership that models healthy boundaries. Individual self-care alone is insufficient without organizational support.", difficulty: 4, category: "Ethics & Professional Boundaries", topic: "Self-Care for Social Workers", questionType: "PRIORITIZATION" },
  { id: "sw-1465", stem: "What is the 'Stages of Change' model and how does it apply to substance use treatment?", options: ["A rigid, linear progression through treatment", "A model (Prochaska and DiClemente) identifying five stages—precontemplation, contemplation, preparation, action, and maintenance—that describes how individuals move through readiness for behavior change, with interventions matched to each stage for optimal effectiveness", "Only applicable to smoking cessation", "A model requiring clients to be in the action stage to receive services"], correctIndex: 1, rationale: "The Stages of Change model: Precontemplation (no intention to change), Contemplation (considering change, ambivalent), Preparation (planning change), Action (actively modifying behavior), and Maintenance (sustaining change). Relapse is common and clients may cycle through stages multiple times. Matching interventions to stage: MI for precontemplation/contemplation, skills training for preparation/action, relapse prevention for maintenance. Requiring action-stage readiness as a prerequisite for services excludes those who need engagement most.", difficulty: 1, category: "Addictions & Substance Use", topic: "ACT", questionType: "MCQ" },
  { id: "sw-1466", stem: "A social worker facilitating a domestic violence support group observes that a new member is sharing very detailed accounts of her abuse, causing visible distress in other members. The facilitator should:", options: ["Allow unlimited sharing to be supportive", "Gently intervene to balance the new member's need to share with the group's emotional safety, acknowledge her courage in sharing, set guidelines about the level of detail appropriate for the group, and check in with other members", "Ask the member to leave the group", "Ignore the reactions of other members"], correctIndex: 1, rationale: "Group facilitators must balance individual needs with group safety. Detailed trauma narratives can retraumatize other members (secondary traumatic stress in the group). The facilitator should: validate the new member's experience and courage, gently guide the level of detail ('You can share what happened without needing to include every detail'), check in with the group ('How is everyone doing?'), establish norms about sharing, and follow up individually with both the sharer and distressed members. This protects group cohesion and safety.", difficulty: 4, category: "Crisis Intervention", topic: "Domestic Violence", questionType: "CASE_VIGNETTE" },
  { id: "sw-1467", stem: "What is the 'person-in-environment' (PIE) perspective in social work?", options: ["Only assessing the client's home environment", "A foundational social work framework that understands human behavior as the product of dynamic interactions between individuals and their multilayered environments (social, economic, political, cultural, physical), guiding comprehensive assessment and intervention at multiple system levels", "A housing assessment tool", "The same as the medical model"], correctIndex: 1, rationale: "The person-in-environment perspective is a core social work framework distinguishing the profession from other helping disciplines. It recognizes that individuals exist within and are shaped by multiple interacting systems: microsystems (family, peers), mesosystems (interactions between microsystems), exosystems (community, workplace), macrosystems (culture, policy, economy), and chronosystems (historical context). Assessment and intervention address both person-level and environmental factors, reflecting social work's dual focus on individual well-being and social conditions.", difficulty: 1, category: "Assessment & Intervention Planning", topic: "Crisis Assessment", questionType: "MCQ" },
  { id: "sw-1468", stem: "A social worker in an emergency department assesses a patient brought in after a suicide attempt by overdose. After medical stabilization, the next priority is:", options: ["Discharge the patient with outpatient referral", "Conduct a thorough suicide risk assessment including current ideation, intent, plan, access to means, risk and protective factors, and determine the appropriate level of care (voluntary vs. involuntary hospitalization, crisis stabilization, or safety planning with close follow-up)", "Contact the patient's employer about the attempt", "Administer a personality assessment"], correctIndex: 1, rationale: "After medical stabilization of a suicide attempt, comprehensive risk assessment is the immediate priority. This includes: current suicidal ideation and intent, understanding of the attempt (planned vs. impulsive, desire for death vs. escape, perceived lethality), risk factors (psychiatric diagnosis, substance use, recent losses, previous attempts), protective factors (reasons for living, social support), mental status examination, and determination of appropriate level of care. A recent attempt is a significant risk factor for future attempts, particularly in the days and weeks following.", difficulty: 4, category: "Crisis Intervention", topic: "Suicide Risk", questionType: "PRIORITIZATION" },
  { id: "sw-1469", stem: "Which play therapy technique involves the therapist verbalizing the child's actions during play?", options: ["Interpretation", "Tracking, where the therapist provides a running verbal description of the child's play behaviors ('You're picking up the red crayon. Now you're drawing a big circle.'), which communicates attention, interest, and acceptance", "Directing the play", "Questioning the child about choices"], correctIndex: 1, rationale: "Tracking is a fundamental play therapy skill where the therapist verbally follows the child's play: 'You're putting the animals in a line. Now you're moving the horse over to the fence.' Tracking serves multiple purposes: communicates that the therapist is fully present and attentive, shows acceptance without judgment, helps the child feel seen and heard, builds the therapeutic relationship, and sometimes helps the child become more aware of their own actions. It is descriptive, not interpretive or evaluative.", difficulty: 1, category: "Child & Family Services", topic: "Play Therapy", questionType: "MCQ" },
  { id: "sw-1470", stem: "A social worker notices they are consistently extending sessions with a particular attractive client and sharing personal details they don't share with other clients. This pattern suggests:", options: ["Excellent therapeutic rapport", "A potential boundary violation indicating the development of a dual relationship, requiring immediate consultation with a supervisor to process the countertransference and establish appropriate professional boundaries", "The client has special therapeutic needs", "The social worker is simply more comfortable with this client"], correctIndex: 1, rationale: "The described pattern—extending sessions, increased self-disclosure, differential treatment based on attraction—represents warning signs of boundary erosion that could lead to a dual relationship or exploitation. The social worker should: recognize the countertransference, seek immediate clinical supervision, examine the motivations behind the behaviors, re-establish professional boundaries, consider transfer of the client if objectivity cannot be maintained, and document the consultation. Self-awareness and proactive boundary management are essential ethical practices.", difficulty: 3, category: "Ethics & Professional Boundaries", topic: "Burnout Prevention", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1471", stem: "In Bowlby's attachment theory, what characterizes 'anxious-ambivalent' (preoccupied) attachment?", options: ["Comfort with independence and relationships", "High anxiety about abandonment, preoccupation with attachment figures, alternating between clingy and angry behavior, difficulty being soothed, and a negative model of self combined with a positive model of others", "Complete avoidance of attachment", "Disorganized and frightening behaviors"], correctIndex: 1, rationale: "Anxious-ambivalent (resistant) attachment develops from inconsistent caregiving. The child learns that the caregiver is sometimes available and sometimes not, leading to: hyperactivation of the attachment system, preoccupation with the caregiver's availability, difficulty using the caregiver as a secure base, mixed approach-avoidance behavior upon reunion, and difficulty being soothed. In adults, this manifests as preoccupied attachment: relationship anxiety, fear of abandonment, need for reassurance, and emotional intensity in relationships.", difficulty: 3, category: "Human Development", topic: "Group Dynamics", questionType: "MCQ" },
  { id: "sw-1472", stem: "A social worker is developing a grant proposal for a homelessness prevention program. Which data would be most compelling to include?", options: ["Only anecdotal stories from clients", "A combination of local homelessness data, evidence-based research supporting the proposed intervention model, cost-benefit analysis showing potential savings to emergency systems, and outcome data from similar programs in comparable communities", "Only the program budget", "Only national homelessness statistics"], correctIndex: 1, rationale: "Compelling grant proposals combine multiple data sources: local needs assessment data (homelessness counts, demographic data, service gaps), evidence base for the proposed intervention (research supporting Housing First, rapid rehousing, prevention), cost-benefit analysis (comparing program costs to emergency room, shelter, and criminal justice costs), outcome data from similar programs, community support letters, and a clear logic model connecting activities to outcomes. This comprehensive approach demonstrates both the need and the likelihood of success.", difficulty: 3, category: "Assessment & Intervention Planning", topic: "Homelessness Interventions", questionType: "MCQ" },
  { id: "sw-1473", stem: "What is 'parallel process' in clinical supervision?", options: ["Supervisors and supervisees doing the same work", "A phenomenon where the dynamics of the therapeutic relationship are unconsciously replicated in the supervisory relationship, providing valuable information about the client-therapist dynamic when recognized and explored", "Reviewing cases simultaneously", "Two supervisors working with the same supervisee"], correctIndex: 1, rationale: "Parallel process occurs when patterns from the client-therapist relationship are enacted in the supervisory relationship (and vice versa). For example, if a client is avoidant with the therapist, the therapist may become avoidant with the supervisor about that case. When recognized, parallel process provides rich clinical data: the supervisor experiences firsthand what the therapist is experiencing with the client. Skillful supervisors use this awareness to deepen the supervisee's understanding of the therapeutic relationship and guide intervention planning.", difficulty: 5, category: "Clinical Practice", topic: "Group Dynamics", questionType: "MCQ" },
  { id: "sw-1474", stem: "A social worker is working with an immigrant family where the parents use physical discipline practices that are culturally normative in their country of origin but may constitute abuse in the United States. The social worker should:", options: ["Immediately report the family to child protective services", "Engage the family in a culturally responsive conversation about U.S. child welfare laws, understand their cultural context, provide psychoeducation on alternative discipline strategies, and assess whether the child is at risk of harm while balancing cultural humility with child safety obligations", "Accept the practices as culturally appropriate", "Avoid discussing discipline to maintain rapport"], correctIndex: 1, rationale: "This situation requires balancing cultural responsiveness with child safety. The social worker should: understand the cultural context without condoning harmful practices, educate the family about U.S. laws regarding physical discipline, provide culturally responsive alternatives to physical punishment, assess the severity and risk of harm to the child, consult with colleagues and supervisors, and fulfill mandatory reporting obligations if the child is at risk. Cultural practices are not exempt from child protection laws, but engagement should be respectful and educational rather than punitive.", difficulty: 4, category: "Diversity, Equity & Inclusion", topic: "Immigration Social Work", questionType: "APPLIED_ETHICS" },
  { id: "sw-1475", stem: "A social worker is reviewing their caseload and realizes they have not been using outcome measures to evaluate treatment effectiveness. Implementing measurement-based care would involve:", options: ["Only administering measures at intake and discharge", "Regularly administering brief, validated outcome measures (such as the PHQ-9 for depression or GAD-7 for anxiety) at each session to track progress, identify clients who are not improving, and adjust treatment approaches based on data", "Replacing clinical judgment with test scores", "Using measures only when required by insurance"], correctIndex: 1, rationale: "Measurement-based care involves systematic, ongoing assessment of treatment outcomes using validated instruments. Benefits include: tracking individual client progress over time, identifying clients who are deteriorating or not improving (allowing early intervention), informing treatment planning decisions with data, enhancing clinical judgment (not replacing it), increasing accountability, and improving overall treatment outcomes. Research shows that therapists who use routine outcome monitoring achieve better client outcomes than those who rely solely on clinical judgment.", difficulty: 2, category: "Assessment & Intervention Planning", topic: "Research Methods", questionType: "MCQ" }
];
